const input = $input.first().json;
const body = input.body ?? input;
const action = String(body.action ?? '').trim();
const requestId = String(
  body.request_id
  ?? body.requestId
  ?? `seo-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`
);

const data = body.data ?? body.payload ?? body.brief ?? {};

const allowedActions = new Set([
  'health',
  'research_sources',
  'generate_outline',
  'generate_article',
  'extract_med_questions',
  'apply_med_answers',
  'validate_article',
  'revise_article',
  'approve_outline',
  'load_existing_article',
  'load_dictionaries',
  'assistant_chat',
  'start_external_uniqueness',
  'get_external_uniqueness',
  'assistant_refresh_knowledge',
  'create_bitrix_draft',
  'draft_health',
  'draft_list',
  'draft_get',
  'draft_create',
  'draft_save_version',
  'draft_list_versions',
  'draft_get_version',
  'draft_restore_version',
  'draft_archive',
  'draft_unarchive',
  'draft_purge',
  'transcribe_case'
]);

const isDraftAction = action.startsWith('draft_');
const isTranscribeAction = action === 'transcribe_case';

function fail(errorCode, message, httpStatus = 400, details = {}) {
  return [{
    json: {
      valid: false,
      success: false,
      action,
      request_id: requestId,
      error_code: errorCode,
      message,
      details,
      http_status: httpStatus
    }
  }];
}

if (!allowedActions.has(action)) {
  return fail(
    'UNKNOWN_ACTION',
    'Неизвестное действие.',
    400,
    { allowed_actions: [...allowedActions] }
  );
}

const generationId = String(
  body.generation_id
  ?? data.generation_id
  ?? `gen-${Date.now()}-${Math.random().toString(36).slice(2, 10)}`
);

function compactJson(value) {
  return JSON.stringify(value ?? {}, null, 2);
}

function articleFromPayload(payload) {
  return payload.article
    ?? payload.result
    ?? payload.current_article
    ?? {
      name: payload.result_name ?? '',
      code: payload.result_code ?? '',
      seo_title: payload.result_seo_title ?? '',
      meta_description: payload.result_meta_description ?? '',
      preview_text: payload.result_preview ?? '',
      short_answer: payload.result_short_answer ?? '',
      detail_html: payload.result_detail_html ?? '',
      sources: payload.result_sources ?? '',
      related_articles: payload.result_related_articles ?? ''
    };
}

const commonRules = `
Ты — медицинский SEO-редактор сети клиник TEMED.

ОБЯЗАТЕЛЬНЫЕ ПРАВИЛА:
1. Работай только с данными, переданными в JSON. Не придумывай факты о TEMED, врачах, клиниках, методах, ценах, длительности, количестве процедур и результатах.
2. Внутренние факты TEMED и комментарии врача имеют приоритет. Их смысл нельзя менять.
3. Не ставь заочный диагноз и не назначай лечение конкретному читателю.
4. Не обещай результат и не используй гарантии эффективности.
5. Числа и медицинские утверждения допускаются только при наличии указанного источника. Если источника нет, убери точное число или пометь утверждение как требующее проверки.
6. Не выдумывай статьи, исследования, DOI, PMID, URL, клинические рекомендации или цитаты.
7. Ответ возвращай только как один корректный JSON-объект без markdown и без пояснений вокруг JSON.
8. Язык результата — русский.
`;

let direct = false;
let response = null;
let prompt = '';

if (action === 'health') {
  direct = true;
  response = {
    success: true,
    action,
    request_id: requestId,
    generation_id: generationId,
    data: {
      status: 'ok',
      workflow: 'TEMED SEO Editor v1',
      ai_model: 'gpt-5.4-mini'
    }
  };
}

if (action === 'approve_outline') {
  direct = true;
  response = {
    success: true,
    action,
    request_id: requestId,
    generation_id: generationId,
    data: {
      approved: true,
      outline: data.generated_outline ?? data.outline ?? ''
    }
  };
}

if (action === 'load_existing_article' || action === 'load_dictionaries') {
  direct = true;
  response = {
    success: true,
    action,
    request_id: requestId,
    generation_id: generationId,
    data: {
      handled_by: 'TEMED SEO PHP proxy',
      message: 'Это действие выполняется напрямую через защищённый PHP proxy, без n8n.'
    }
  };
}


if (action === 'assistant_chat') {
  const systemContext = body.system_context ?? data.system_context ?? {};
  prompt = `${commonRules}

ЗАДАЧА:
Ответь как ассистент редактора TEMED SEO Editor в режиме ${data.mode ?? 'article'}. Используй live system_manifest, article_structures, summary dictionaries и текущие поля статьи. Верни JSON строго в формате: {"answer":"","sources":[],"suggestions":[],"warnings":[]}. Suggestions не применяются автоматически и требуют requires_confirmation=true. Не предлагай правки секретов, endpoint, credential, config и hidden security fields. Медицинские формулировки помечай как требующие ручного подтверждения.

LIVE SYSTEM CONTEXT:
${compactJson(systemContext)}

ARTICLE/EDITOR CONTEXT:
${compactJson(data)}
`;
}


if (action === 'assistant_refresh_knowledge') {
  direct = true;
  response = {success: true, action, request_id: requestId, generation_id: generationId, data: {status: 'scheduled', allowed_files: ['README.md', 'docs/**', 'internal/seo-editor/assets/js/**', 'n8n/TEMED SEO Editor.json']}};
}

if (action === 'create_bitrix_draft') {
  direct = true;
  response = {
    success: false,
    action,
    request_id: requestId,
    generation_id: generationId,
    error_code: 'WRITE_API_DISABLED',
    message: 'Запись в Bitrix отключена. Workflow работает в безопасном read-only режиме.',
    http_status: 501
  };
}

if (action === 'research_sources') {
  prompt = `${commonRules}

ЗАДАЧА:
Подготовь исследовательский пакет по теме статьи.

Важно: у тебя нет права объявлять источник проверенным только по названию или URL.
Раздели источники на:
- user_provided — источник дал редактор;
- metadata_only — можно оценить только по переданным метаданным;
- needs_manual_verification — требуется ручная проверка полного текста;
- rejected — источник не подходит или недостаточно данных.

Не выдумывай новые библиографические записи.
Допускается предложить только поисковые запросы для PubMed, Google Scholar, российских клинических рекомендаций и сайтов профильных профессиональных обществ.

ФОРМАТ:
{
  "approved_sources_text": "строки только по источникам, которые можно оставить редактору на утверждение",
  "candidates": [
    {
      "title": "",
      "url": "",
      "source_type": "",
      "status": "user_provided|metadata_only|needs_manual_verification|rejected",
      "why_relevant": "",
      "limitations": ""
    }
  ],
  "search_queries": [
    {
      "database": "PubMed|Google Scholar|Клинические рекомендации РФ|Профессиональное общество",
      "query": "",
      "purpose": ""
    }
  ],
  "claims_needing_sources": [],
  "warnings": []
}

ДАННЫЕ:
${compactJson(data)}
`;
}

if (action === 'generate_outline') {
  prompt = `${commonRules}

ЗАДАЧА:
Составь подробный план медицинской SEO-статьи строго по выбранной структуре.
Если в данных передан structure_config, соблюдай порядок, обязательность, repeat, instructions, global_instructions, forbidden и seo.
Не пиши саму статью.

ФОРМАТ:
{
  "outline_text": "редактируемый текстовый план",
  "outline": [
    {
      "order": 1,
      "block": "",
      "heading": "",
      "heading_level": "intro|h2|h3",
      "required": true,
      "purpose": "",
      "key_points": [],
      "source_requirements": [],
      "medical_review_points": []
    }
  ],
  "missing_information": [],
  "warnings": []
}

ДАННЫЕ:
${compactJson(data)}
`;
}

if (action === 'generate_article') {
  prompt = `${commonRules}

ЗАДАЧА:
Подготовь полный черновик статьи по утверждённому плану и выбранной структуре.

ТРЕБОВАНИЯ К HTML:
- detail_html содержит только содержимое статьи, без html, head и body;
- используй h2, h3, p, ul, ol, table, blockquote;
- не используй inline-стили, script, iframe;
- первый абзац должен сразу отвечать на основной запрос, если структура не требует иного;
- источники в тексте должны соответствовать массиву sources;
- дисклеймер обязателен;
- не добавляй несуществующие формы, цены и контакты.

ФОРМАТ:
{
  "name": "",
  "code": "",
  "seo_title": "",
  "meta_description": "",
  "preview_text": "",
  "short_answer": "",
  "detail_html": "",
  "sources": [
    {
      "title": "",
      "url": "",
      "identifier": "",
      "used_for": []
    }
  ],
  "related_articles": [],
  "medical_review_questions": [
    {
      "id": "M1",
      "fragment": "",
      "question": "",
      "reason": ""
    }
  ],
  "warnings": []
}

ДАННЫЕ:
${compactJson(data)}
`;
}

if (action === 'extract_med_questions') {
  const article = articleFromPayload(data);
  prompt = `${commonRules}

ЗАДАЧА:
Проведи медицинскую редакторскую проверку готовой статьи.
Не переписывай текст.
Выдели только формулировки, которые требуют подтверждения врача:
- конкретные схемы, сроки, дозировки, число процедур;
- показания и противопоказания;
- причинно-следственные медицинские утверждения;
- прогноз и ожидаемый эффект;
- спорные или слишком категоричные утверждения;
- данные без источника.

ФОРМАТ:
{
  "questions_text": "пронумерованный список для передачи врачу",
  "questions": [
    {
      "id": "M1",
      "fragment": "",
      "question": "",
      "reason": "",
      "suggested_safe_wording": ""
    }
  ],
  "critical_count": 0,
  "warnings": []
}

СТАТЬЯ:
${compactJson(article)}

КОНТЕКСТ:
${compactJson(data)}
`;
}

if (action === 'apply_med_answers') {
  const article = articleFromPayload(data);
  prompt = `${commonRules}

ЗАДАЧА:
Внеси ответы медицинского редактора в статью точечно.
Меняй только те фрагменты, к которым относятся ответы.
Не улучшай стиль остального текста и не генерируй статью заново.
Если ответ врача неоднозначен, не меняй фрагмент и добавь предупреждение.

ФОРМАТ:
{
  "article": {
    "name": "",
    "code": "",
    "seo_title": "",
    "meta_description": "",
    "preview_text": "",
    "short_answer": "",
    "detail_html": "",
    "sources": [],
    "related_articles": []
  },
  "changes": [
    {
      "question_id": "",
      "before": "",
      "after": "",
      "status": "changed|deleted|unchanged"
    }
  ],
  "unresolved_questions": [],
  "warnings": []
}

ИСХОДНАЯ СТАТЬЯ:
${compactJson(article)}

ВОПРОСЫ И ОТВЕТЫ:
${compactJson({
  questions: data.med_questions ?? data.questions ?? '',
  answers: data.med_answers ?? data.answers ?? ''
})}
`;
}

if (action === 'validate_article') {
  const article = articleFromPayload(data);
  prompt = `${commonRules}

ЗАДАЧА:
Проверь статью перед публикацией. Ничего не переписывай.

ПРОВЕРКИ:
- наличие обязательных блоков выбранной структуры;
- выполнение дополнительных требований;
- нарушения forbidden и YMYL;
- гарантии результата, заочная диагностика и назначения;
- числа и медицинские утверждения без источника;
- соответствие источников тексту;
- title, description, code, preview, short_answer;
- HTML: запрещённые теги, незакрытые конструкции, дубли H1;
- дисклеймер;
- логичность CTA;
- соответствие автора и медредактора переданным данным.

ФОРМАТ:
{
  "passed": false,
  "score": 0,
  "report_text": "",
  "errors": [
    {
      "code": "",
      "severity": "critical|major|minor",
      "location": "",
      "message": "",
      "recommended_fix": ""
    }
  ],
  "warnings": [],
  "checks": [
    {
      "name": "",
      "passed": true,
      "details": ""
    }
  ]
}

СТАТЬЯ:
${compactJson(article)}

ТЕХНИЧЕСКОЕ ЗАДАНИЕ:
${compactJson(data)}
`;
}

if (action === 'revise_article') {
  const article = articleFromPayload(data);
  prompt = `${commonRules}

ЗАДАЧА:
Переработай только фрагменты, прямо указанные в замечаниях.
Не меняй согласованные части, структуру, факты TEMED и ответы врача без необходимости.
Верни полный объект статьи после точечной правки.

ФОРМАТ:
{
  "article": {
    "name": "",
    "code": "",
    "seo_title": "",
    "meta_description": "",
    "preview_text": "",
    "short_answer": "",
    "detail_html": "",
    "sources": [],
    "related_articles": []
  },
  "changed_sections": [
    {
      "location": "",
      "reason": "",
      "before": "",
      "after": ""
    }
  ],
  "unresolved_comments": [],
  "warnings": []
}

ИСХОДНАЯ СТАТЬЯ:
${compactJson(article)}

ЗАМЕЧАНИЯ:
${compactJson(data.revision_request ?? data.comments ?? data.validation_report ?? '')}

КОНТЕКСТ:
${compactJson(data)}
`;
}

if (!direct && !prompt && !isDraftAction && !isTranscribeAction) {
  return fail(
    'ACTION_NOT_IMPLEMENTED',
    'Для действия не сформирован обработчик.',
    501
  );
}

return [{
  json: {
    valid: true,
    success: true,
    direct,
    is_draft_action: isDraftAction,
    is_transcribe_action: isTranscribeAction,
    action,
    request_id: requestId,
    generation_id: generationId,
    data,
    prompt,
    response,
    http_status: response?.http_status ?? 200
  }
}];

const prepared = $node['Prepare request'].json;

let raw =
  $json.message?.content
  ?? $json.text
  ?? $json.content
  ?? $json.output
  ?? $json.response
  ?? '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

function extractObject(text) {
  try {
    return JSON.parse(text);
  } catch (_) {}

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');

  if (start >= 0 && end > start) {
    return JSON.parse(text.slice(start, end + 1));
  }

  throw new Error('JSON object not found');
}

try {
  const parsed = extractObject(raw);

  if (!parsed || Array.isArray(parsed) || typeof parsed !== 'object') {
    throw new Error('Model returned non-object JSON');
  }

  return [{
    json: {
      success: true,
      action: prepared.action,
      request_id: prepared.request_id,
      generation_id: prepared.generation_id,
      data: parsed,
      meta: {
        model: 'gpt-5.4-mini',
        workflow: 'TEMED SEO Editor v1',
        completed_at: new Date().toISOString()
      },
      http_status: 200
    }
  }];
} catch (error) {
  return [{
    json: {
      success: false,
      action: prepared.action,
      request_id: prepared.request_id,
      generation_id: prepared.generation_id,
      error_code: 'MODEL_JSON_PARSE_ERROR',
      message: 'Модель вернула ответ, который не удалось разобрать как JSON.',
      details: {
        error: String(error.message || error),
        raw_preview: raw.slice(0, 2000)
      },
      http_status: 502
    }
  }];
}

const prepared = $input.first().json;
const data = prepared.data ?? {};
const text = data.text;
const contentHash = data.content_hash;
function fail(errorCode, message, httpStatus = 400) {
  return [{json: {success: false, action: prepared.action, request_id: prepared.request_id, generation_id: prepared.generation_id, error_code: errorCode, message, http_status: httpStatus}}];
}
let payloadSize = 0;
try { payloadSize = JSON.stringify(data).length; } catch (_) { payloadSize = 0; }
if (payloadSize > 170000) return fail('TEXT_RU_PAYLOAD_TOO_LARGE', 'Payload для TEXT.RU превышает лимит workflow.', 413);
if (typeof text !== 'string') return fail('TEXT_RU_TEXT_REQUIRED', 'Для проверки TEXT.RU требуется текст строкой.', 400);
const trimmed = text.trim();
if (!trimmed) return fail('TEXT_RU_TEXT_REQUIRED', 'Для проверки TEXT.RU требуется непустой текст.', 400);
if (trimmed.length < 100) return fail('TEXT_TOO_SHORT_FOR_TEXT_RU', 'Для проверки TEXT.RU требуется не менее 100 символов.', 400);
if (trimmed.length > 150000) return fail('TEXT_TOO_LONG_FOR_TEXT_RU', 'TEXT.RU принимает не более 150000 символов.', 400);
if (typeof contentHash !== 'string' || !contentHash.trim()) return fail('TEXT_RU_CONTENT_HASH_REQUIRED', 'Для проверки TEXT.RU требуется content_hash.', 400);
return [{json: {action: prepared.action, request_id: prepared.request_id, generation_id: prepared.generation_id, content_hash: contentHash.trim(), text: trimmed, submitted_at: new Date().toISOString()}}];

function textRuError(action, requestId, generationId, raw, ctx = {}) {
  const code = Number(raw?.error_code ?? raw?.code ?? 0);
  const desc = String(raw?.error_desc ?? raw?.message ?? '').slice(0, 500);
  const base = {success: false, action, request_id: requestId, generation_id: generationId, data: {status: 'failed', provider: 'text.ru', content_hash: ctx.content_hash, text_uid: ctx.text_uid}};
  const validation = new Set([110,111,112,113,150]);
  const credential = new Set([120,121,170,171,141,146]);
  const provider = new Set([140,143,144,145,151,182,183]);
  if (validation.has(code)) return {...base, error_code: code === 112 ? 'TEXT_TOO_SHORT_FOR_TEXT_RU' : code === 113 ? 'TEXT_TOO_LONG_FOR_TEXT_RU' : 'TEXT_RU_VALIDATION_ERROR', message: desc || 'TEXT.RU отклонил текст для проверки.', http_status: 400};
  if (credential.has(code)) return {...base, error_code: 'TEXT_RU_CREDENTIAL_ERROR', message: 'Не удалось авторизоваться в TEXT.RU. Проверьте credential TEXT.RU API.', http_status: 502};
  if (code === 142) return {...base, error_code: 'TEXT_RU_INSUFFICIENT_BALANCE', message: 'На балансе TEXT.RU недостаточно символов для проверки.', http_status: 402};
  if (code === 160 || code === 161) return {...base, error_code: 'TEXT_RU_UID_INVALID', message: desc || 'TEXT.RU требует корректный UID проверки.', http_status: 400};
  if (code === 180) return {...base, error_code: 'TEXT_RU_UID_NOT_FOUND', message: 'TEXT.RU не нашёл результат для указанного UID.', http_status: 404};
  if (code === 429) return {...base, error_code: 'TEXT_RU_RATE_LIMIT', message: 'TEXT.RU временно ограничил количество запросов.', data: {...base.data, retry_after_seconds: 60}, http_status: 429};
  if (provider.has(code)) return {...base, error_code: 'TEXT_RU_PROVIDER_ERROR', message: code === 182 ? 'Проверка завершилась ошибкой на стороне TEXT.RU.' : (desc || 'TEXT.RU временно не смог выполнить проверку.'), http_status: 502};
  return {...base, error_code: 'TEXT_RU_PROVIDER_ERROR', message: desc || 'TEXT.RU вернул ошибку.', http_status: 502};
}

const raw = $input.first().json;
const ctx = $node['Prepare TEXT.RU submit'].json;
if (raw?.error_code !== undefined) return [{json: textRuError(ctx.action, ctx.request_id, ctx.generation_id, raw, ctx)}];
const textUid = typeof raw?.text_uid === 'string' ? raw.text_uid.trim() : '';
if (!textUid) return [{json: {success: false, action: ctx.action, request_id: ctx.request_id, generation_id: ctx.generation_id, error_code: 'TEXT_RU_INVALID_RESPONSE', message: 'TEXT.RU не вернул text_uid.', data: {status: 'failed', content_hash: ctx.content_hash, provider: 'text.ru'}, http_status: 502}}];
return [{json: {success: true, action: ctx.action, request_id: ctx.request_id, generation_id: ctx.generation_id, data: {status: 'processing', text_uid: textUid, content_hash: ctx.content_hash, submitted_at: ctx.submitted_at, retry_after_seconds: 15, provider: 'text.ru'}, http_status: 200}}];

const prepared = $input.first().json;
const data = prepared.data ?? {};
const uid = data.text_uid ?? data.uid;
const contentHash = data.content_hash;
function fail(errorCode, message, httpStatus = 400) { return [{json: {success: false, action: prepared.action, request_id: prepared.request_id, generation_id: prepared.generation_id, error_code: errorCode, message, http_status: httpStatus}}]; }
if (typeof uid !== 'string' || !uid.trim()) return fail('TEXT_RU_UID_REQUIRED', 'Для запроса результата TEXT.RU требуется text_uid.', 400);
const textUid = uid.trim();
if (textUid.length > 200 || /[\u0000-\u001F\u007F]/.test(textUid)) return fail('TEXT_RU_UID_INVALID', 'UID TEXT.RU имеет недопустимый формат.', 400);
