  rows.sort((a, b) => String(b.UPDATED_AT || '').localeCompare(String(a.UPDATED_AT || '')));
  const total = rows.length;
  rows = rows.slice(offset, offset + limit).map(draftMetadata);
  return [{json: {direct: true, requests: [], response: {success: true, action, request_id: requestId, data: {items: rows,total,limit,offset}, http_status: 200}, http_status: 200}}];
}

if (action === 'draft_get') {
