if (action === 'draft_create' || action === 'draft_save_version' || action === 'draft_restore_version') {
  let draft = action === 'draft_create' ? null : draftById(data.draft_id);
  if (action !== 'draft_create' && !draft) return responseError('DRAFT_NOT_FOUND', 'Черновик не найден.', 404);
  if (action !== 'draft_create') {
    const expected = number(data.expected_current_version, -1);
    const actual = number(draft.CURRENT_VERSION, 0);
    if (expected !== actual) {
      return responseError('VERSION_CONFLICT', 'Черновик уже был изменён в другой вкладке.', 409, {expected, actual});
    }
  }

  let snapshot = data.snapshot;
  if (action === 'draft_restore_version') {
    try {
      const loaded = reconstruct(String(data.version_id || ''));
      snapshot = loaded.snapshot;
    } catch (error) {
      const [code, message, status] = errorFromException(error);
      return responseError(code, message, status);
    }
  }

  let pkg;
  try {
    pkg = snapshotPackage(snapshot);
  } catch (error) {
    const [code, message, status] = errorFromException(error);
    return responseError(code, message, status);
  }

  const timestamp = now();
  const draftId = draft ? String(draft.DRAFT_ID) : uuid('draft');
  const versionId = uuid('version');
  const versionNumber = draft ? number(draft.CURRENT_VERSION, 0) + 1 : 1;
