  const status = normalizeStatus(metadata.status ?? draft?.STATUS, 'active');
  const comment = String(metadata.save_comment ?? data.save_comment ?? '');

  const snapshotRows = pkg.chunks.map((chunk, index) => ({
    VERSION_ID: versionId,
    DRAFT_ID: draftId,
    CHUNK_INDEX: index + 1,
    CHUNK_COUNT: pkg.chunks.length,
    SNAPSHOT_CHUNK: chunk,
    SNAPSHOT_HASH: pkg.hash,
    SNAPSHOT_SIZE: pkg.size,
    CREATED_AT: timestamp
  }));

  const versionRow = {
    VERSION_ID: versionId,
    DRAFT_ID: draftId,
    VERSION_NUMBER: versionNumber,
    SAVED_AT: timestamp,
    SAVE_COMMENT: comment,
    SNAPSHOT_HASH: pkg.hash,
    SNAPSHOT_SIZE: pkg.size,
    SNAPSHOT_CHUNKS: pkg.chunks.length,
    SNAPSHOT_ENCODING: pkg.encoding
  };

  const mergedDraft = {
    DRAFT_ID: draftId,
    NAME: String(metadata.name ?? draft?.NAME ?? snapshot?.article?.name ?? snapshot?.fields?.result_name ?? 'Без названия'),
    STATUS: status,
    LAST_COMMENT: comment,
    CURRENT_VERSION: versionNumber,
    CURRENT_VERSION_ID: versionId,
    CREATED_AT: draft?.CREATED_AT || timestamp,
    UPDATED_AT: timestamp,
    SNAPSHOT_HASH: pkg.hash,
    SNAPSHOT_SIZE: pkg.size,
    SNAPSHOT_CHUNKS: pkg.chunks.length,
    SNAPSHOT_ENCODING: pkg.encoding
  };

  const requests = [
    appendRequest('Снимки', snapshotRows),
    appendRequest('Версии', [versionRow]),
    draft ? updateRowRequest('Черновики', draft.__row_number, mergedDraft) : appendRequest('Черновики', [mergedDraft])
  ];

  return [{
    json: {
      direct: false,
      requests,
      response: {
        success: true,
        action,
        request_id: requestId,
        data: {
          draft_id: draftId,
          version_id: versionId,
          version_number: versionNumber,
          snapshot_hash: pkg.hash,
          snapshot_size: pkg.size,
          snapshot_chunks: pkg.chunks.length
        },
        http_status: action === 'draft_create' ? 201 : 200
      },
      http_status: action === 'draft_create' ? 201 : 200
    }
  }];
}

if (action === 'draft_archive' || action === 'draft_unarchive') {
  const draft = draftById(data.draft_id);
  if (!draft) return responseError('DRAFT_NOT_FOUND', 'Черновик не найден.', 404);
  const updated = {...draft};
  delete updated.__row_number;
