    return [...rowNumbers]
      .sort((a, b) => b - a)
      .map(rowNumber => ({
        deleteDimension: {
          range: {
            sheetId,
            dimension: 'ROWS',
            startIndex: rowNumber - 1,
            endIndex: rowNumber
          }
        }
      }));
  }

  const draftId = String(draft.DRAFT_ID);
  const deleteRequests = [
    ...deleteRequestsForRows('Снимки', getSheet('Снимки').rows.filter(row => String(row.DRAFT_ID || '') === draftId).map(row => row.__row_number)),
    ...deleteRequestsForRows('Версии', getSheet('Версии').rows.filter(row => String(row.DRAFT_ID || '') === draftId).map(row => row.__row_number)),
    ...deleteRequestsForRows('Черновики', [draft.__row_number])
  ];

  const requests = [
    {
      method: 'POST',
      url: `https://sheets.googleapis.com/v4/spreadsheets/${spreadsheetId}:batchUpdate`,
      body: {requests: deleteRequests}
    }
  ];

  return [{json: {direct: false, requests, response: {success: true, action, request_id: requestId, data: {draft_id: draftId, purged: true}, http_status: 200}, http_status: 200}}];
}

