const allowedMime = new Set([
  'audio/ogg',
  'audio/mpeg',
  'audio/mp4',
  'audio/x-m4a',
  'audio/wav',
  'audio/webm'
]);

const extByMime = {
  'audio/ogg': 'ogg',
  'audio/mpeg': 'mp3',
  'audio/mp4': 'mp4',
  'audio/x-m4a': 'm4a',
  'audio/wav': 'wav',
  'audio/webm': 'webm'
};

const mimeType = String(data.mime_type ?? '').trim().toLowerCase();
const base64 = String(data.audio_base64 ?? '').trim();
const filenameRaw = String(data.filename ?? '').trim();

function fail(errorCode, message, httpStatus = 400, details = {}) {
  return [{
    json: {
      valid: false,
      success: false,
      action,
      request_id: requestId,
      error_code: errorCode,
      message,
      details,
      http_status: httpStatus
    }
  }];
}

if (!base64) {
  return fail('EMPTY_AUDIO', 'Аудиофайл не передан.');
}

if (!allowedMime.has(mimeType)) {
  return fail('UNSUPPORTED_MIME', 'Неподдерживаемый тип аудио.', 400, {
    mime_type: mimeType,
    allowed_mime: [...allowedMime]
  });
}

const padding = base64.endsWith('==') ? 2 : (base64.endsWith('=') ? 1 : 0);
const sizeBytes = Math.max(0, Math.floor(base64.length * 3 / 4) - padding);
const maxBytes = 25 * 1024 * 1024;

if (sizeBytes > maxBytes) {
  return fail('AUDIO_TOO_LARGE', 'Аудиофайл превышает 25 МБ.', 413, {
    size_bytes: sizeBytes,
    max_bytes: maxBytes
  });
}

const ext = extByMime[mimeType];
const hasExt = /\.[a-z0-9]{1,5}$/i.test(filenameRaw);
const baseName = filenameRaw.replace(/\.[a-z0-9]{1,5}$/i, '') || 'case-audio';
const fileName = hasExt ? filenameRaw : `${baseName}.${ext}`;

return [{
  json: {
    valid: true,
    action,
    request_id: requestId,
    filename: fileName,
    mime_type: mimeType,
    size_bytes: sizeBytes
  },
  binary: {
    data: {
      data: base64,
      mimeType,
      fileName,
      fileExtension: ext
    }
  }
}];

