const prep = $('Prepare case processing').first().json;
const transcriptRaw = String(prep.transcript_raw ?? '').trim();

let raw =
  $json.message?.content
  ?? $json.text
  ?? $json.content
  ?? $json.output
  ?? $json.response
  ?? '';

if (typeof raw !== 'string') {
  raw = JSON.stringify(raw);
}

raw = raw
  .trim()
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

function extractObject(text) {
  try {
    return JSON.parse(text);
  } catch (_) {}

  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');

  if (start >= 0 && end > start) {
    return JSON.parse(text.slice(start, end + 1));
  }

  throw new Error('JSON object not found');
}

const base = {
  success: true,
  action: prep.action ?? 'transcribe_case',
  request_id: prep.request_id
};

try {
  const parsed = extractObject(raw);

  if (!parsed || Array.isArray(parsed) || typeof parsed !== 'object') {
    throw new Error('Model returned non-object JSON');
  }

  const cleaned = String(parsed.cleaned_transcript ?? '').trim();
  const summary = String(parsed.summary ?? '').trim();
  const topics = Array.isArray(parsed.topics)
    ? parsed.topics.map((t) => ({
        title: String(t?.title ?? '').trim(),
        primary_query: String(t?.primary_query ?? '').trim(),
        fit: String(t?.fit ?? '').trim()
      })).filter((t) => t.title || t.primary_query)
    : [];

  return [{
    json: {
      ...base,
      data: {
        transcript_raw: transcriptRaw,
        transcript: cleaned || transcriptRaw,
        summary,
        topics
      },
      http_status: 200
    }
  }];
} catch (error) {
  return [{
    json: {
      ...base,
      processing_failed: true,
      data: {
        transcript_raw: transcriptRaw,
        transcript: transcriptRaw,
        summary: '',
        topics: [],
        processing_failed: true
      },
      details: {
        error: String(error.message || error),
        raw_preview: raw.slice(0, 2000)
      },
      http_status: 200
    }
  }];
}
